    plt.close()
    print(f"\n│  Saved results/phase41e_best_combined.png", flush=True)

    print(f"\n{'=' * 70}", flush=True)
    if mass_acc > 93 and fc_success > 80:
        verdict = "SUCCESS"
    elif mass_acc > 90 or fc_success > 65:
        verdict = "PARTIAL"
    else:
        verdict = "FAIL"
    print(f"VERDICT: {verdict}", flush=True)
    print(f"  Mass accuracy:        {mass_acc:.1f}% (target >93%)", flush=True)
    print(f"  Elasticity accuracy:  {elast_acc:.1f}% (target >40%)", flush=True)
    print(f"  Joint accuracy:       {joint_acc:.1f}%", flush=True)
    print(f"  Full pipeline:        {fc_success:.1f}% (target >80%)", flush=True)
    print(f"  Oracle comm:          {oc_success:.1f}%", flush=True)
    print(f"  No communication:     {nc_success:.1f}%", flush=True)
