    run_phase26f()

    total = time.time() - t0
    print(f"\n{'='*60}")
    print(f"ALL PHASES COMPLETE in {total:.0f}s ({total/60:.1f} min)")
    print(f"Results: {OUTPUT_DIR}/")
    for f in sorted(OUTPUT_DIR.iterdir()):
        print(f"  {f}")
